#!/bin/bash
GREEN='\033[0;32m'; BLUE='\033[0;34m'; YELLOW='\033[1;33m'; RED='\033[0;31m'; NC='\033[0m'
echo ""
echo -e "${BLUE}╔══════════════════════════════════════════════╗${NC}"
echo -e "${BLUE}║   Beme Marketplace — Full Install (bash)     ║${NC}"
echo -e "${BLUE}╚══════════════════════════════════════════════╝${NC}"
echo ""
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
FE="$SCRIPT_DIR/Beme-Frontend"
BE="$SCRIPT_DIR/Beme-Backend"
if [ ! -d "$FE/src" ]; then echo -e "${RED}✗ Cannot find Beme-Frontend/src${NC}"; exit 1; fi
if [ ! -d "$BE/src" ]; then echo -e "${RED}✗ Cannot find Beme-Backend/src${NC}"; exit 1; fi
echo -e "${BLUE}► Frontend:${NC} $FE"
echo -e "${BLUE}► Backend: ${NC} $BE"
echo ""
mkdir -p "$FE/src/services" "$FE/src/components" "$FE/src/pages/dashboard" "$BE/src/routes"

echo -e "${YELLOW}[1/7] Writing Beme-Frontend/src/services/chatService.js…${NC}"
echo "" | base64 -d > "$SCRIPT_DIR/Beme-Frontend/src/services/chatService.js"
echo -e "  ${GREEN}✓${NC} Beme-Frontend/src/services/chatService.js"

echo -e "${YELLOW}[2/7] Writing Beme-Frontend/src/components/ChatModal.jsx…${NC}"
echo "" | base64 -d > "$SCRIPT_DIR/Beme-Frontend/src/components/ChatModal.jsx"
echo -e "  ${GREEN}✓${NC} Beme-Frontend/src/components/ChatModal.jsx"

echo -e "${YELLOW}[3/7] Writing Beme-Frontend/src/pages/Chat.jsx…${NC}"
echo "" | base64 -d > "$SCRIPT_DIR/Beme-Frontend/src/pages/Chat.jsx"
echo -e "  ${GREEN}✓${NC} Beme-Frontend/src/pages/Chat.jsx"

echo -e "${YELLOW}[4/7] Writing Beme-Backend/src/routes/chatRoutes.js…${NC}"
echo "" | base64 -d > "$SCRIPT_DIR/Beme-Backend/src/routes/chatRoutes.js"
echo -e "  ${GREEN}✓${NC} Beme-Backend/src/routes/chatRoutes.js"

echo -e "${YELLOW}[5/7] Writing Beme-Frontend/src/pages/dashboard/DashboardAppearance.jsx…${NC}"
echo "" | base64 -d > "$SCRIPT_DIR/Beme-Frontend/src/pages/dashboard/DashboardAppearance.jsx"
echo -e "  ${GREEN}✓${NC} Beme-Frontend/src/pages/dashboard/DashboardAppearance.jsx"

echo -e "${YELLOW}[6/7] Writing Beme-Backend/src/app.js…${NC}"
echo "" | base64 -d > "$SCRIPT_DIR/Beme-Backend/src/app.js"
echo -e "  ${GREEN}✓${NC} Beme-Backend/src/app.js"

echo -e "${YELLOW}[7/7] Writing Beme-Frontend/src/pages/StoreFront.jsx…${NC}"
echo "" | base64 -d > "$SCRIPT_DIR/Beme-Frontend/src/pages/StoreFront.jsx"
echo -e "  ${GREEN}✓${NC} Beme-Frontend/src/pages/StoreFront.jsx"

echo ""
echo -e "${GREEN}╔══════════════════════════════════════════════╗${NC}"
echo -e "${GREEN}║   ✓  All 7 files installed!                  ║${NC}"
echo -e "${GREEN}╚══════════════════════════════════════════════╝${NC}"
echo ""
echo -e "${YELLOW}Manual steps needed:${NC}"
echo -e "  1. Open ProductDetails.jsx and add:"
echo -e "     import ChatModal from \"../components/ChatModal\";  (top)"
echo -e "     const [showChat, setShowChat] = useState(false);    (in SellerInfoPanel)"
echo -e "     onClick={() => setShowChat(true)}                   (Chat button)"
echo -e "     {showChat && <ChatModal shop={shop2} onClose={() => setShowChat(false)} />}"
echo ""
echo -e "  2. Add to App.jsx routes:"
echo -e "     import Chat from \"./pages/Chat\";"
echo -e "     <Route path=\"/messages\" element={<Chat />} />"
echo ""
echo -e "${BLUE}Deploy:${NC}"
echo -e "  cd Beme-Backend && git add . && git commit -m \"Add chat backend\" && git push"
echo -e "  cd ../Beme-Frontend && git add . && git commit -m \"Add marketplace chat + storefront\" && git push"
echo ""